// Simplified scoring for Phase 1
const job=items[0].json;const user=$('User Profile').item.json;
const skills=(user.skills||[]).map(s=>s.toLowerCase());
const desc=(job.description||'').toLowerCase();
let score=40;
skills.forEach(s=>{if(desc.includes(s))score+=12;});
if(job.workMode==='Remote')score+=5;
if(job.priority==='HIGH')score+=5;
score=Math.min(score,100);
return [{json:{...job,score}}];
